import type {
  ReactElement,
  MouseEvent as ReactMouseEvent,
  RefObject,
} from 'react';

import type { IntentProps } from '../../../../core/slots/Intent/Intent.js';
import type { BehaviorTrackingProps } from '../../../../core/types/behavior-tracking-props.js';
import type {
  A11yToolbarTabIndex,
  InternalChartToolbarConfig,
} from '../../types/toolbar.js';

/**
 * @internal
 */
export const menuDisplayModes = [
  'collapsed',
  'expanded',
  'always',
  'never',
] as const;

/**
 * @internal
 */
export type MenuDisplayMode = (typeof menuDisplayModes)[number];

/**
 * @internal
 */
export type IntentsAsyncTemplate = () => Promise<ReactElement>;

/**
 * @internal
 */
export type ToolbarHanderRef = { handleFocus: () => void };

/**
 * @internal
 */
export interface ChartToolbarRendererProps
  extends InternalChartToolbarConfig,
    BehaviorTrackingProps {
  /** Whether the toolbar is visible or not */
  visible: boolean;
  /** Initial state of the A11yToolbar */
  initialA11yState: A11yToolbarTabIndex[];
  /** zIndex for the chart toolbar area */
  zIndex?: number;
  /** The function called when the toolbar manually collapses/expands */
  onToggleToolbar?: (value: boolean) => void;
  /** The function called when the menu opens/closes */
  onToggleMenu?: (value: boolean) => void;
  /** The function called when mouse enters the toolbar */
  onMouseEnter?: (event?: ReactMouseEvent<HTMLDivElement, MouseEvent>) => void;
  /** The function called when mouse leaves the toolbar */
  onMouseLeave?: (event?: ReactMouseEvent<HTMLDivElement, MouseEvent>) => void;
  /** Icon of the active mode shown in the menu trigger button */
  menuIcon?: ReactElement;
  /** Defines a tooltip text for the dropdown menu trigger button */
  menuTriggerLabel?: string;
  /** Indicates, when the menu should be available to be triggered on the toolbar
   * - collapsed: only shown on menu trigger on collapsed toolbar (no menu on expanded toolbar)
   * - expanded: only shown on menu trigger on expanded toolbar (toolbar becomes not collapsable)
   * - always: always show the menu trigger
   * - never: never show the menu trigger
   *
   * @defaultValue 'collapsed'
   * */
  menuDisplayMode?: MenuDisplayMode;
  /**
   *  If set to true, the drag handle will be removed and the whole toolbar will be draggable.
   *  @defaultValue false
   */
  removeDragHandle?: boolean;
  /** Action to perform while closing toolbar menu */
  onClose?: () => void;
  isDownloadEnabled?: boolean;
  intents?: Array<IntentProps>;
  handleDownloadDataToolbar?: () => void;
  /** Display mode for the toolbar area
   * @defaultValue 'overlay'
   **/
  toolbarDisplayMode?: 'overlay' | 'inline';
  visibleWhenMouseInBounds?: boolean;
  /** Additional class name for the toolbar area */
  overlayClassName?: string;
  intentsAsyncTemplate?: IntentsAsyncTemplate;
  handlerRef?: RefObject<ToolbarHanderRef>;
}
